use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

/// Compares two real numbers with six significant digits precision
/// Returns "LT" if a < b, "EQ" if a == b, "GT" if a > b
pub fn realcompare(a: f64, b: f64) -> &'static str {
    let epsilon = 1e-6;

    // Handle special cases
    if a.is_nan() || b.is_nan() {
        return "EQ";
    }

    // For very small numbers near zero
    if a.abs() < epsilon && b.abs() < epsilon {
        return "EQ";
    }

    // Calculate relative difference for six significant digits
    let diff = a - b;
    let avg = (a.abs() + b.abs()) / 2.0;

    if avg < epsilon {
        if diff.abs() < epsilon {
            return "EQ";
        }
    } else {
        // Six significant digits means relative error of 1e-6
        if (diff / avg).abs() < epsilon {
            return "EQ";
        }
    }

    if diff < 0.0 {
        "LT"
    } else {
        "GT"
    }
}

/// Calculate distance between two points
fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

/// Calculate the angle formed by three points (p1, vertex, p2)
/// Returns None if angle is undefined (coincident points)
fn angle(x1: f64, y1: f64, x_vertex: f64, y_vertex: f64, x2: f64, y2: f64) -> Option<f64> {
    // Check if first or last point coincides with vertex
    if (x1 == x_vertex && y1 == y_vertex) || (x2 == x_vertex && y2 == y_vertex) {
        return None;
    }

    // Calculate vectors from vertex to first and last points
    let v1x = x1 - x_vertex;
    let v1y = y1 - y_vertex;
    let v2x = x2 - x_vertex;
    let v2y = y2 - y_vertex;

    // Calculate dot product and magnitudes
    let dot = v1x * v2x + v1y * v2y;
    let mag1 = (v1x * v1x + v1y * v1y).sqrt();
    let mag2 = (v2x * v2x + v2y * v2y).sqrt();

    // Calculate angle using arccos
    let cos_angle = dot / (mag1 * mag2);
    // Clamp to [-1, 1] to avoid numerical errors
    let cos_angle = cos_angle.max(-1.0).min(1.0);
    Some(cos_angle.acos())
}

/// Calculate area of triangle formed by three points
fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    0.5 * ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs())
}

/// Find the smallest circle containing three points
/// Returns the radius of the smallest enclosing circle
fn smallest_circle_radius(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    let d12 = distance(x1, y1, x2, y2);
    let d23 = distance(x2, y2, x3, y3);
    let d13 = distance(x1, y1, x3, y3);

    // If any two points are the same, return the max distance
    if d12 < 1e-10 {
        return d23.max(d13);
    }
    if d23 < 1e-10 {
        return d12.max(d13);
    }
    if d13 < 1e-10 {
        return d12.max(d23);
    }

    // Check if the triangle is obtuse
    let sides = [d12, d23, d13];
    let max_side = sides.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
    let max_idx = sides.iter().position(|&x| x == max_side).unwrap();

    // Check if angle opposite to max side is obtuse
    match max_idx {
        0 => {
            // d12 is longest, check angle at point 3
            if d13 * d13 + d23 * d23 < d12 * d12 {
                return d12 / 2.0;
            }
        }
        1 => {
            // d23 is longest, check angle at point 1
            if d12 * d12 + d13 * d13 < d23 * d23 {
                return d23 / 2.0;
            }
        }
        2 => {
            // d13 is longest, check angle at point 2
            if d12 * d12 + d23 * d23 < d13 * d13 {
                return d13 / 2.0;
            }
        }
        _ => {}
    }

    // Triangle is acute, use circumradius formula
    let area = triangle_area(x1, y1, x2, y2, x3, y3);
    if area < 1e-10 {
        // Points are collinear
        return max_side / 2.0;
    }

    (d12 * d23 * d13) / (4.0 * area)
}

/// Calculate distance from a point to a line segment
fn point_to_line_distance(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    // If the line endpoints are the same, return distance to that point
    if x1 == x2 && y1 == y2 {
        return distance(px, py, x1, y1);
    }

    // Distance from point to line using cross product formula
    let num = ((y2 - y1) * px - (x2 - x1) * py + x2 * y1 - y2 * x1).abs();
    let den = ((y2 - y1).powi(2) + (x2 - x1).powi(2)).sqrt();
    num / den
}

/// Determine which quadrant a point is in (1-4, corresponding to I-IV)
fn quadrant(x: f64, y: f64) -> usize {
    if realcompare(x, 0.0) != "LT" && realcompare(y, 0.0) != "LT" {
        1 // Quadrant I: x >= 0, y >= 0
    } else if realcompare(x, 0.0) == "LT" && realcompare(y, 0.0) != "LT" {
        2 // Quadrant II: x < 0, y >= 0
    } else if realcompare(x, 0.0) == "LT" && realcompare(y, 0.0) == "LT" {
        3 // Quadrant III: x < 0, y < 0
    } else {
        4 // Quadrant IV: x >= 0, y < 0
    }
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let mut cmv = vec![false; 15];

    // LIC 1: Two consecutive points distance > LENGTH1
    for i in 0..input.numpoints - 1 {
        let dist = distance(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]);
        if realcompare(dist, input.parameters.length1) == "GT" {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2: Three consecutive points cannot be contained in circle of radius RADIUS1
    if input.numpoints >= 3 {
        for i in 0..input.numpoints - 2 {
            let radius = smallest_circle_radius(
                input.x[i], input.y[i],
                input.x[i + 1], input.y[i + 1],
                input.x[i + 2], input.y[i + 2]
            );
            if realcompare(radius, input.parameters.radius1) == "GT" {
                cmv[1] = true;
                break;
            }
        }
    }

    // LIC 3: Three consecutive points form angle < PI-EPSILON or > PI+EPSILON
    if input.numpoints >= 3 {
        for i in 0..input.numpoints - 2 {
            if let Some(ang) = angle(
                input.x[i], input.y[i],
                input.x[i + 1], input.y[i + 1],
                input.x[i + 2], input.y[i + 2]
            ) {
                if realcompare(ang, PI - input.parameters.epsilon) == "LT" ||
                   realcompare(ang, PI + input.parameters.epsilon) == "GT" {
                    cmv[2] = true;
                    break;
                }
            }
        }
    }

    // LIC 4: Three consecutive points form triangle with area > AREA1
    if input.numpoints >= 3 {
        for i in 0..input.numpoints - 2 {
            let area = triangle_area(
                input.x[i], input.y[i],
                input.x[i + 1], input.y[i + 1],
                input.x[i + 2], input.y[i + 2]
            );
            if realcompare(area, input.parameters.area1) == "GT" {
                cmv[3] = true;
                break;
            }
        }
    }

    // LIC 5: Q_PTS consecutive points in more than QUADS quadrants
    if input.numpoints >= input.parameters.q_pts {
        for i in 0..=input.numpoints - input.parameters.q_pts {
            let mut quads_seen = vec![false; 4];
            for j in 0..input.parameters.q_pts {
                let q = quadrant(input.x[i + j], input.y[i + j]);
                quads_seen[q - 1] = true;
            }
            let num_quads = quads_seen.iter().filter(|&&x| x).count();
            if num_quads > input.parameters.quads {
                cmv[4] = true;
                break;
            }
        }
    }

    // LIC 6: Two consecutive points with X[j] - X[i] < 0
    for i in 0..input.numpoints - 1 {
        if realcompare(input.x[i + 1], input.x[i]) == "LT" {
            cmv[5] = true;
            break;
        }
    }

    // LIC 7: N_PTS consecutive points with one point distance > DIST from line
    if input.numpoints >= 3 {
        if input.numpoints >= input.parameters.n_pts {
            for i in 0..=input.numpoints - input.parameters.n_pts {
                let first = i;
                let last = i + input.parameters.n_pts - 1;

                // Check if first and last are identical
                if input.x[first] == input.x[last] && input.y[first] == input.y[last] {
                    // Distance from coincident point to all others
                    for j in first..=last {
                        let dist = distance(
                            input.x[j], input.y[j],
                            input.x[first], input.y[first]
                        );
                        if realcompare(dist, input.parameters.dist) == "GT" {
                            cmv[6] = true;
                            break;
                        }
                    }
                } else {
                    // Distance from points to line joining first and last
                    for j in first..=last {
                        let dist = point_to_line_distance(
                            input.x[j], input.y[j],
                            input.x[first], input.y[first],
                            input.x[last], input.y[last]
                        );
                        if realcompare(dist, input.parameters.dist) == "GT" {
                            cmv[6] = true;
                            break;
                        }
                    }
                }

                if cmv[6] {
                    break;
                }
            }
        }
    }

    // LIC 8: Two points separated by K_PTS with distance > LENGTH1
    if input.numpoints >= 3 {
        for i in 0..input.numpoints {
            let j = i + input.parameters.k_pts + 1;
            if j < input.numpoints {
                let dist = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
                if realcompare(dist, input.parameters.length1) == "GT" {
                    cmv[7] = true;
                    break;
                }
            }
        }
    }

    // LIC 9: Three points separated by A_PTS and B_PTS, cannot fit in circle of radius RADIUS1
    if input.numpoints >= 5 {
        for i in 0..input.numpoints {
            let j = i + input.parameters.a_pts + 1;
            let k = j + input.parameters.b_pts + 1;
            if k < input.numpoints {
                let radius = smallest_circle_radius(
                    input.x[i], input.y[i],
                    input.x[j], input.y[j],
                    input.x[k], input.y[k]
                );
                if realcompare(radius, input.parameters.radius1) == "GT" {
                    cmv[8] = true;
                    break;
                }
            }
        }
    }

    // LIC 10: Three points separated by C_PTS and D_PTS form angle < PI-EPSILON or > PI+EPSILON
    if input.numpoints >= 5 {
        for i in 0..input.numpoints {
            let j = i + input.parameters.c_pts + 1;
            let k = j + input.parameters.d_pts + 1;
            if k < input.numpoints {
                if let Some(ang) = angle(
                    input.x[i], input.y[i],
                    input.x[j], input.y[j],
                    input.x[k], input.y[k]
                ) {
                    if realcompare(ang, PI - input.parameters.epsilon) == "LT" ||
                       realcompare(ang, PI + input.parameters.epsilon) == "GT" {
                        cmv[9] = true;
                        break;
                    }
                }
            }
        }
    }

    // LIC 11: Three points separated by E_PTS and F_PTS form triangle with area > AREA1
    if input.numpoints >= 5 {
        for i in 0..input.numpoints {
            let j = i + input.parameters.e_pts + 1;
            let k = j + input.parameters.f_pts + 1;
            if k < input.numpoints {
                let area = triangle_area(
                    input.x[i], input.y[i],
                    input.x[j], input.y[j],
                    input.x[k], input.y[k]
                );
                if realcompare(area, input.parameters.area1) == "GT" {
                    cmv[10] = true;
                    break;
                }
            }
        }
    }

    // LIC 12: Two points separated by G_PTS with X[j] - X[i] < 0
    if input.numpoints >= 3 {
        for i in 0..input.numpoints {
            let j = i + input.parameters.g_pts + 1;
            if j < input.numpoints {
                if realcompare(input.x[j], input.x[i]) == "LT" {
                    cmv[11] = true;
                    break;
                }
            }
        }
    }

    // LIC 13: Two points separated by K_PTS with distance > LENGTH1 AND
    //         two points separated by K_PTS with distance < LENGTH2
    if input.numpoints >= 3 {
        let mut condition1 = false;
        let mut condition2 = false;

        for i in 0..input.numpoints {
            let j = i + input.parameters.k_pts + 1;
            if j < input.numpoints {
                let dist = distance(input.x[i], input.y[i], input.x[j], input.y[j]);
                if realcompare(dist, input.parameters.length1) == "GT" {
                    condition1 = true;
                }
                if realcompare(dist, input.parameters.length2) == "LT" {
                    condition2 = true;
                }
            }
        }

        cmv[12] = condition1 && condition2;
    }

    // LIC 14: Three points separated by A_PTS and B_PTS cannot fit in RADIUS1 AND
    //         three points separated by A_PTS and B_PTS can fit in RADIUS2
    if input.numpoints >= 5 {
        let mut condition1 = false;
        let mut condition2 = false;

        for i in 0..input.numpoints {
            let j = i + input.parameters.a_pts + 1;
            let k = j + input.parameters.b_pts + 1;
            if k < input.numpoints {
                let radius = smallest_circle_radius(
                    input.x[i], input.y[i],
                    input.x[j], input.y[j],
                    input.x[k], input.y[k]
                );
                if realcompare(radius, input.parameters.radius1) == "GT" {
                    condition1 = true;
                }
                if realcompare(radius, input.parameters.radius2) == "LT" ||
                   realcompare(radius, input.parameters.radius2) == "EQ" {
                    condition2 = true;
                }
            }
        }

        cmv[13] = condition1 && condition2;
    }

    // LIC 15: Three points separated by E_PTS and F_PTS with area > AREA1 AND
    //         three points separated by E_PTS and F_PTS with area < AREA2
    if input.numpoints >= 5 {
        let mut condition1 = false;
        let mut condition2 = false;

        for i in 0..input.numpoints {
            let j = i + input.parameters.e_pts + 1;
            let k = j + input.parameters.f_pts + 1;
            if k < input.numpoints {
                let area = triangle_area(
                    input.x[i], input.y[i],
                    input.x[j], input.y[j],
                    input.x[k], input.y[k]
                );
                if realcompare(area, input.parameters.area1) == "GT" {
                    condition1 = true;
                }
                if realcompare(area, input.parameters.area2) == "LT" {
                    condition2 = true;
                }
            }
        }

        cmv[14] = condition1 && condition2;
    }

    // Compute PUM from CMV and LCM
    let mut pum = vec![vec![false; 15]; 15];

    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                // Diagonal elements come from input
                pum[i][j] = input.pum_diag[i];
            } else {
                // Off-diagonal elements computed from LCM and CMV
                match input.lcm[i][j].as_str() {
                    "NOTUSED" => pum[i][j] = true,
                    "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                    "ORR" => pum[i][j] = cmv[i] || cmv[j],
                    _ => pum[i][j] = false,
                }
            }
        }
    }

    // Compute FUV from PUM
    let mut fuv = vec![false; 15];

    for i in 0..15 {
        if !pum[i][i] {
            // PUM[i,i] is false, so FUV[i] is true
            fuv[i] = true;
        } else {
            // Check if all elements in row i are true
            fuv[i] = (0..15).all(|j| pum[i][j]);
        }
    }

    // Compute LAUNCH
    let launch = fuv.iter().all(|&x| x);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
